package problems;

public class maxiumSubarray {

    public static void main(String[] args) {

        int[] nums = {-2,1,-3,4,-1,2,1,-5,4};
        System.out.println("Maximum sub array sum " + maxSubarraySum(nums));
        System.out.println("Maximum sub array poduct " + maxSubarrayProduct(nums));


    }

    public static int maxSubarraySum(int[] nums){
        // Given an integer array nums, find the contiguous subarray (containing at least one number) which has the largest sum and return its sum.
        // A subarray is a contiguous part of an array.
        // Example 1:
        // Input: nums = [-2,1,-3,4,-1,2,1,-5,4]
        // Output: 6
        // Explanation: [4,-1,2,1] has the
        // largest sum = 6.

        int current = 0 , max = nums[0];
        for(int i =0;i<nums.length;i++){
            if(current <0){
                current = 0;
            }
            current = current + nums[i];
            max = Math.max(max,current);
        }
        return max;
    }
    public static int maxSubarrayProduct(int[] nums){
        // Given an integer array nums, find a contiguous non-empty subarray within the array that has the largest product, and return the product.
        // The test cases are generated so that the answer will fit in a 32-bit integer.
        // A subarray is a contiguous subsequence of the array.
        // Example 1:
        // Input: nums = [2,3,-2,4]
        // Output: 6
        if(nums.length == 0 ) return 0;
        int max = nums[0] , min = nums[0] , result = max;
        for(int i =0;i<nums.length;i++){
            int curr = nums[i];
            int temp = Math.max(curr,Math.max(max*curr , min*curr));
            min = Math.min(curr,Math.max(max*curr , min*curr));
            max = temp;
            result = Math.max(result,max);
        }
        return result;
    }
}
